interface Config {
  host: string;
  port: number;
  debug: boolean;
}

const defaults: Config = {
  host: "localhost",
  port: 3000,
  debug: false,
};

function applyConfig(base: Config, overrides: Partial<Config>): Config {
  return { ...base, ...overrides };
}

const prod = applyConfig(defaults, { host: "api.example.com", debug: false });
console.log(prod.host);
console.log(prod.port);
console.log(prod.debug);

interface Article {
  id: number;
  title: string;
  content: string;
  authorId: number;
  publishedAt: string;
}

type ArticlePreview = Pick<Article, "id" | "title" | "publishedAt">;
type ArticleInput = Omit<Article, "id" | "publishedAt">;

const preview: ArticlePreview = {
  id: 1,
  title: "TypeScript Tips",
  publishedAt: "2024-01-15",
};

console.log(preview.title);
console.log(Object.keys(preview).join(", "));

type Lang = "go" | "python" | "typescript";
type LangInfo = Record<Lang, { icon: string; level: string }>;

const languages: LangInfo = {
  go:         { icon: "🐹", level: "intermediate" },
  python:     { icon: "🐍", level: "beginner" },
  typescript: { icon: "🔷", level: "intermediate" },
};

for (const [lang, info] of Object.entries(languages)) {
  console.log(`${info.icon} ${lang}: ${info.level}`);
}

function createUser(name: string, age: number, admin: boolean) {
  return { name, age, admin, createdAt: new Date().getFullYear() };
}

type UserResult = ReturnType<typeof createUser>;
type CreateParams = Parameters<typeof createUser>;

const params: CreateParams = ["Alice", 30, false];
const user: UserResult = createUser(...params);

console.log(user.name);
console.log(user.age);
console.log(user.admin);
